// Planilla de nómina — v0.2 (constantes + dividida)

const SALUD_RATE = 0.04;
const PENSION_RATE = 0.04;
const HORAS_NORMALES = 40;
const EXTRA_RATE = 1.5;

function calcularSalario(emp) {
  let bruto = emp.salarioBase;
  if (emp.horas > HORAS_NORMALES) {
    const extras = emp.horas - HORAS_NORMALES;
    bruto = bruto + extras * emp.tarifa * EXTRA_RATE;
  }
  const salud = bruto * SALUD_RATE;
  const pension = bruto * PENSION_RATE;
  return { bruto, neto: bruto - salud - pension };
}

function procesarPlanilla(empleados) {
  const resultados = [];
  for (let i = 0; i < empleados.length; i++) {
    const r = calcularSalario(empleados[i]);
    resultados.push({ nombre: empleados[i].nombre, bruto: r.bruto, neto: r.neto });
  }
  return resultados;
}

