const emps = [{ nombre: 'Ana', salarioBase: 3000, horas: 40, tarifa: 50 }];
const r = procesarPlanilla(emps);
if (r.length !== 1) throw new Error('Debe devolver 1 resultado');
const esperado = 3000 - 3000 * 0.04 * 2;
if (Math.abs(r[0].neto - esperado) > 0.01)
  throw new Error(`Esperado ${esperado}, recibido ${r[0].neto}`);

const emps = [{ nombre: 'Beto', salarioBase: 2000, horas: 45, tarifa: 100 }];
const r = procesarPlanilla(emps);
const bruto = 2000 + 5 * 100 * 1.5;
const esperado = bruto - bruto * 0.04 * 2;
if (Math.abs(r[0].neto - esperado) > 0.01)
  throw new Error(`Esperado ${esperado}, recibido ${r[0].neto}`);

const emps = [
  { nombre: 'A', salarioBase: 1000, horas: 40, tarifa: 10 },
  { nombre: 'B', salarioBase: 2000, horas: 40, tarifa: 10 },
];
const r = procesarPlanilla(emps);
